class DefaultWalletClient : WalletClient {
    override suspend fun charge(request: PaymentRequest): PaymentResult = withContext(Dispatchers.IO) {
        val amount = request.amount?.normalized()
        if (amount == null) {
            return@withContext PaymentResult(
                requestId = request.orderId,
                status = PaymentStatus.FAILED,
                message = "Missing amount"
            )
        }
        if (amount.amount <= BigDecimal.ZERO) {
            return@withContext PaymentResult(
                requestId = request.orderId,
                status = PaymentStatus.FAILED,
                message = "Invalid amount"
            )
        }
        PaymentResult(
            requestId = request.orderId,
            status = PaymentStatus.SUCCESS,
            transactionId = UUID.randomUUID().toString(),
            message = "Wallet transaction completed"
        )
    }

    override suspend fun refund(request: PaymentRequest): PaymentResult = withContext(Dispatchers.IO) {
        PaymentResult(
            requestId = request.orderId,
            status = PaymentStatus.SUCCESS,
            transactionId = UUID.randomUUID().toString(),
            message = "Wallet refund completed"
        )
    }
}

class SecureCryptoManager {
    private val secretKey: SecretKey by lazy { createKey() }

    fun encrypt(data: ByteArray): SecurePayload {
        val cipher = Cipher.getInstance(TRANSFORMATION)
        cipher.init(Cipher.ENCRYPT_MODE, secretKey)
        val iv = cipher.iv ?: ByteArray(0)
        val ciphertext = cipher.doFinal(data)
        return SecurePayload(iv = iv, ciphertext = ciphertext)
    }

    fun decrypt(payload: SecurePayload): ByteArray {
        val cipher = Cipher.getInstance(TRANSFORMATION)
        val spec = GCMParameterSpec(payload.authenticationTagLengthBits, payload.iv)
        cipher.init(Cipher.DECRYPT_MODE, secretKey, spec)
        return cipher.doFinal(payload.ciphertext)
    }

    private fun createKey(): SecretKey {
        val keyGenerator = KeyGenerator.getInstance(KEY_ALGORITHM)
        keyGenerator.init(256)
        return keyGenerator.generateKey()
    }

    private companion object {
        private const val KEY_ALGORITHM = "AES"
        private const val TRANSFORMATION = "AES/GCM/NoPadding"
    }
}

